<script setup lang="ts">import {allContent} from '~/data/dummy/content';const route=useRoute();const q=computed(()=>String(route.query.q||''));const results=computed(()=>q.value?allContent.filter(x=>(x.title+x.excerpt).toLowerCase().includes(q.value.toLowerCase())):[]);useSchoolSeo('Pencarian','Cari informasi Sekolah SAKTI')</script><template><div class="container-school py-12"><h1 class="text-3xl font-bold text-school-navy">Pencarian</h1><form class="mt-6 flex max-w-2xl gap-2" action="/pencarian"><label class="sr-only" for="q">Kata kunci</label><input id="q" name="q" :value="q" class="min-w-0 flex-1 rounded-xl border border-line bg-white px-4" placeholder="Cari berita, agenda, program..."><button class="btn btn-primary">Cari</button></form><p class="mt-6 text-muted">{{results.length}} hasil untuk “{{q}}”</p><div class="mt-5 grid gap-3"><article v-for="x in results" :key="x.id" class="card p-5"><b class="text-school-navy">{{x.title}}</b><p class="mt-1 text-sm text-muted">{{x.excerpt}}</p></article></div></div></template>
